```cpp
#include <iostream>
// Check if a number is prime using basic iteration loop
bool isPrime(int n) {
    if (n <= 1) return false;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) return false;
    }
    return true;
}
